scwin.ondataload = function () {
  scwin.f_Set("INIT");
  acb_userClsCd_param.setSelectedIndex(0);
  ed_zip.setEditFormat('###-#||###-##||###-###'); // -를 자리수 로 먹어서 maxLength 6-> 7
};

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
  switch (gubun) {
    case "INIT":
      //초기화
      scwin.f_ContentsDisable();
      rd_useYn_param.setValue(1);
      acb_userClsCd_param.setSelectedIndex(5);
      lc_userClsCd.setSelectedIndex(4);
      //			cfDisableObjects([acb_userClsCd_param]);
      $c.gus.cfDisableBtn($p, [b_Update, b_Delete, b_Cancel, b_Save, btnAddRow, btnDeleteRow, btnUndoRow]);
      $c.gus.cfEnableBtnOnly($p, [b_Create]);
      break;
    case "RETRIEVE":
      //초기화
      scwin.f_ContentsDisable();
      $c.gus.cfDisableBtn($p, [b_Cancel, b_Save, btnAddRow, btnDeleteRow, btnUndoRow]);
      $c.gus.cfEnableBtnOnly($p, [b_Create, b_Update, b_Delete]);
      break;
    case "CREATE":
      scwin.f_ContentsEnable();
      $c.gus.cfEnableBtnOnly($p, [b_Cancel, b_Save, btnAddRow, btnDeleteRow, btnUndoRow]);
      $c.gus.cfDisableBtn($p, [b_Create, b_Delete, b_Update]);
      break;
    case "UPDATE":
      scwin.f_ContentsEnable();
      $c.gus.cfEnableBtnOnly($p, [b_Cancel, b_Save, btnAddRow, btnDeleteRow, btnUndoRow]);
      $c.gus.cfDisableBtn($p, [b_Create, b_Delete, b_Update]);
      break;
    case "DELETE":
      scwin.f_ContentsEnable();
      $c.gus.cfEnableBtnOnly($p, [b_Cancel, b_Save]);
      $c.gus.cfDisableBtn($p, [b_Create, b_Delete, b_Update, btnAddRow, btnDeleteRow, btnUndoRow]);
      break;
  }
};

