//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  let vUserClsCd = scwin.txt_userClsCd;
  let vUserId = ed_userId.getValue().trimAll();
  // let vDecPasswd = txt_decPasswd.getValue().trimAll();
  let vCheckUserIdSearchYn = scwin.txt_checkUserDupl;
  //let vRowStatus = dma_search_cond.RowStatus(oGDS_search_cond.RowPosition);
  let vPasswordExceptYn = passwordExceptYn.getValue();
  let vNewPassword = ed_newPasswd.getValue();
  let vNewPasswordConfirm = ed_newPasswdConfirm.getValue();
  let vUserRowStatus = ds_result_list.getRowStatus(ds_result_list.getRowPosition());
  if (!scwin.f_userIdCheck(vUserId)) {
    ed_userId.focus();
    return false;
  }
  if (!scwin.f_passwordCheck(vUserId, vNewPassword)) {
    ed_newPasswd.focus();
    return false;
  }

  // 사용자 등록인 경우만 비밀번호 필수
  if (vUserRowStatus == 'C') {
    ed_newPasswd.setMandatory(true);
    //txt_newPasswd.validExp = "신규비밀번호:yes";

    ed_newPasswdConfirm.setMandatory(true);
    //txt_newPasswdConfirm.validExp = "신규비밀번호확인:yes";

    //$c.gus.cfRefreshMandSign();
  } else if (vUserRowStatus == 'U') {
    ed_newPasswd.setMandatory(false);
    //txt_newPasswd.validExp = "";

    ed_newPasswdConfirm.setMandatory(false);
    //txt_newPasswdConfirm.validExp = "";

    //$c.gus.cfRefreshMandSign();
  }
  if (vPasswordExceptYn) {
    if (vNewPassword != vNewPasswordConfirm) {
      $c.win.alert($p, "신규비밀번호와 신규확인번호는 일치해야합니다.");
      ed_newPasswdConfirm.focus();
      return false;
    }
  } else {
    if (vNewPassword.trimAll() != "") {
      if (vNewPassword != vNewPasswordConfirm) {
        $c.win.alert($p, "신규비밀번호와 신규확인번호는 일치해야합니다.");
        ed_newPasswdConfirm.focus();
        return false;
      }
    }
  }
  for (let i = 0; i < ds_result_list.getRowCount(); i++) {
    if (ds_result_list.getRowStatus(i) == 'U' || ds_result_list.getRowStatus(i) == 'C') {
      // 아이디 계정 차단 관련
      if (ds_result_list.getRowStatus(i) == 'U') {
        scwin.value_useYn = ds_result_list.getCellData(i, "useYn");
        scwin.value_blockReason = ds_result_list.getCellData(i, "blockReason");
        scwin.value_blockDt = ds_result_list.getCellData(i, "blockDt");
        scwin.value_blockEtDt = ds_result_list.getCellData(i, "blockEtDt");
        scwin.value_blockCancelEtDt = ds_result_list.getCellData(i, "blockCancelEtDt");
      } else if (ds_result_list.getRowStatus(i) == 'C') {
        scwin.value_useYn = scwin.selUseYn;
        scwin.value_blockReason = lc_blockReason.getValue();
        scwin.value_blockDt = ed_blockDt.getValue();
        scwin.value_blockEtDt = ed_blockEtDt.getValue();
        scwin.value_blockCancelEtDt = ed_blockCancelEtDt.getValue();
        ds_result_list.setCellData(i, "useYn", scwin.value_useYn);
        ds_result_list.setCellData(i, "blockReason", scwin.value_blockReason);
        ds_result_list.setCellData(i, "blockDt", scwin.value_blockDt);
        ds_result_list.setCellData(i, "blockEtDt", scwin.value_blockEtDt);
        ds_result_list.setCellData(i, "blockCancelEtDt", scwin.value_blockCancelEtDt);
      }
      if (scwin.value_useYn == 2) {
        $c.gus.cfAlertMsg($p, "사용여부를 선택해야 합니다.");
        return false;
      }
      if (scwin.value_blockDt != "" || scwin.value_blockEtDt != "" || scwin.value_blockCancelEtDt != "" || scwin.value_useYn == 0) {
        if (scwin.value_blockReason == "") {
          $c.gus.cfAlertMsg($p, "차단을 하거나 차단예정일자를 지정하는 경우에는 차단 사유를 입력해야 합니다.");
          return false;
        }
      }
      if (scwin.value_useYn == 1) {
        let reason = scwin.value_blockReason;
        if (scwin.value_blockDt != "") {
          $c.gus.cfAlertMsg($p, "사용여부 Yes인 상태에서 차단일자를 설정할 수 없습니다.");
          return false;
        }
        if (scwin.value_blockEtDt == "" && scwin.value_blockReason != "") {
          $c.gus.cfAlertMsg($p, "사용여부 Yes인 상태에서는 차단예정일자를 설정해야 합니다.");
          return false;
        }
        if (reason == "C" || reason == "D") {
          $c.gus.cfAlertMsg($p, "사용여부 Yes인 상태에서 허용되지 않는 차단사유입니다.");
          return false;
        }
        if (reason == "A" || reason == "B" || reason == "E") {
          if (scwin.value_blockEtDt == "") {
            $c.gus.cfAlertMsg($p, "차단예정일자가 필요합니다.");
            return false;
          }
        }
      }

      // 날짜 체크
      scwin.txt_curDate = scwin.strCurDate;
      if (scwin.value_blockEtDt != "") {
        if (!$c.gus.cfIsAfterDate($p, scwin.txt_curDate, scwin.value_blockEtDt) || scwin.txt_curDate == scwin.value_blockEtDt) {
          $c.gus.cfAlertMsg($p, "차단예정일자는 현재 날짜 이후로 입력해 주십시오.");
          ed_blockDt.setValue("");
          ed_blockEtDt.setValue("");
          ed_blockCancelEtDt.setValue("");
          return false;
        }
      }
      if (scwin.value_blockCancelEtDt != "") {
        if (!$c.gus.cfIsAfterDate($p, scwin.txt_curDate, scwin.value_blockCancelEtDt) || scwin.txt_curDate == scwin.value_blockCancelEtDt) {
          $c.gus.cfAlertMsg($p, "차단해지예정일자를 현재 날짜 이후로 입력해 주십시오.");
          ed_blockDt.setValue("");
          ed_blockEtDt.setValue("");
          ed_blockCancelEtDt.setValue("");
          return false;
        }
      }
      if (scwin.value_blockDt != "") {
        if ($c.gus.cfIsAfterDate($p, scwin.txt_curDate, scwin.value_blockDt) && scwin.txt_curDate != scwin.value_blockDt) {
          $c.gus.cfAlertMsg($p, "차단일자는 현재일자까지만 입력이 가능합니다");
          ed_blockDt.setValue("");
          ed_blockEtDt.setValue("");
          ed_blockCancelEtDt.setValue("");
          return false;
        }
      }
      if (scwin.value_blockEtDt != "" && scwin.value_blockDt != "") {
        $c.gus.cfAlertMsg($p, "차단일자와 차단예정일자를 동시에 설정할 수 없습니다.");
        ed_blockDt.setValue("");
        ed_blockEtDt.setValue("");
        ed_blockCancelEtDt.setValue("");
        return false;
      }
      if (scwin.value_blockEtDt != "" && scwin.value_blockCancelEtDt != "") {
        if (!$c.gus.cfIsAfterDate($p, scwin.value_blockEtDt, scwin.value_blockCancelEtDt)) {
          $c.gus.cfAlertMsg($p, "차단 예정 일자를 해지 일자 이전으로 입력해 주십시오.");
          ed_blockDt.setValue("");
          ed_blockEtDt.setValue("");
          ed_blockCancelEtDt.setValue("");
          return false;
        }
      }
    }
  }
  if (vUserRowStatus == 'C' || vUserRowStatus == 'U') {
    if (!(await $c.gus.cfValidate($p, [oRecevInfo]))) {
      return false;
    }
  }
  let vUserPrivGroupDuplCheck = scwin.f_ChkUserPrivGroupSelect();
  if (vUserPrivGroupDuplCheck > 0) {
    $c.win.alert($p, "사용자권한그룹이 중복되었습니다.");
    gr_userPrivGroup.focus();
    return false;
  }
  if (ds_result_list.getModifiedIndex().length == 0 && ds_userPrivGroup.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, new Array("사용자 정보"));
  } else {
    scwin.pos_rowSts = ds_result_list.getRowPosition();
    if (vUserRowStatus == 'C') {
      scwin.txt_SaveType = "1";
    } else if (vUserRowStatus == 'U') {
      scwin.txt_SaveType = "3";
    }
    let vConfirm = await $c.win.confirm($p, "저장하시겠습니까?");
    if (vConfirm) {
      //txt_userId_param.value = txt_userId.value;
      //acb_userClsCd_param.Index = lc_userClsCd.Index + 1;
      ds_userPrivGroup.setCellData(0, "userId", ed_userId.getValue());
      //tr_save.Post();

      $c.sbm.execute($p, sbm_save);
      scwin.f_Retrieve();
      scwin.f_ContentsDisable();
      scwin.flag = 0;
    } else {
      scwin.f_Cancel();
    }
  }
};
scwin.f_userIdCheck = function (vUserId) {
  let vUserClsCd = scwin.txt_userClsCd;
  let iLen = vUserId.length;
  let vFirstChar = vUserId.substr(0, 1);
  let engCnt = $c.gus.cfisEnglishCnt($p, vUserId);
  let numCnt = $c.gus.cfisNumberCnt($p, vUserId);
  if (iLen < 4) {
    $c.win.alert($p, "사용자ID는 4자리 이상이어야 합니다.");
    return false;
  }

  /*
  if ( vUserClsCd != "01" && !cfisEnglish(vFirstChar) )
  {
      alert("사용자ID 첫글자는 영문자 이어야 합니다.");
      return false;
  }
  */
  /*
  if ( engCnt == 0 || numCnt == 0 )
  {
      alert("사용자ID는 영어+숫자 조합이어야 합니다.");
      return false;
  }
  */

  if (engCnt + numCnt != iLen) {
    $c.win.alert($p, "사용자ID는 특수문자를 사용할수 없습니다.");
    return false;
  }
  return true;
};
scwin.f_passwordCheck = function (vUserId, vPassword) {
  let iLen = vPassword.length;
  let engCnt = $c.gus.cfisEnglishCnt($p, vPassword);
  let numCnt = $c.gus.cfisNumberCnt($p, vPassword);
  if (!passwordExceptYn.checked && vPassword == "") return true;
  if ($c.gus.cfnumChainChk($p, vPassword)) {
    $c.win.alert($p, "비밀번호는 연속 또는 동일한  숫자 3자리 이상  사용할 수 없습니다.");
    return false;
  }
  if (iLen < 10) {
    $c.win.alert($p, "비밀번호는 10자리 이상이어야 합니다.");
    return false;
  }
  if (engCnt == 0 || numCnt == 0) {
    $c.win.alert($p, "비밀번호는 영어+숫자 조합이어야 합니다.");
    return false;
  }
  if (vUserId == vPassword) {
    $c.win.alert($p, "사용자ID를 비밀번호로 사용할  수  없습니다.");
    return false;
  }
  return true;
};

