scwin.f_Update = function () {
  scwin.flag = 1;
  let vPasswordExceptYn = passwordExceptYn.getValue();
  if (scwin.vSysAdminYn == "1") {
    passwdExpyn.setDisabled(false);
  } else {
    passwdExpyn.setDisabled(true);
  }
  if (vPasswordExceptYn) {
    scwin.f_ContentsDisable();
    $c.gus.cfEnableObj($p, ed_newPasswd, true); //
    $c.gus.cfEnableObj($p, ed_newPasswdConfirm, true); //		

    //cfDisableBtn([b_Create, b_Update, b_Delete]);
  } else {
    scwin.f_ContentsEnable();

    //cfDisableBtn([b_Create, b_Update, b_Delete]);
  }
  gr_userPrivGroup.setReadOnly(false);
  $c.gus.cfEnableObj($p, ed_userId, false); //
  scwin.txt_checkUserDupl = "";
  ed_newPasswd.setMandatory(false);
  ed_newPasswdConfirm.setMandatory(false);

  //$c.gus.cfRefreshMandSign();

  scwin.editYn = 0;
  $c.gus.cfDisableObjects($p, [lc_blockReason]);
  //$c.gus.cfDisableObjects([calendar_blockDt, calendar_blockCancelEtDt, calendar_blockEtDt]);

  if (rd_useYn.getValue() == "0") {
    if (lc_blockReason.getValue() == "A" || lc_blockReason.getValue() == "B") {
      $c.gus.cfEnableObjects($p, [ed_blockDt, ed_blockCancelEtDt, lc_blockReason]);
      //$c.gus.cfEnableObjects([calendar_blockDt, calendar_blockCancelEtDt ]);			
    } else if (lc_blockReason.getValue() == "C" || lc_blockReason.getValue() == "D") {
      $c.gus.cfEnableObjects($p, [lc_blockReason]);
    } else if (lc_blockReason.getValue() == "E") {
      $c.gus.cfEnableObjects($p, [ed_blockDt, lc_blockReason]);
      //cfEnableObjects([calendar_blockDt]);
    }
  }
  if (rd_useYn.getValue() == "1") {
    $c.gus.cfEnableObjects($p, [lc_blockReason, ed_blockCancelEtDt, ed_blockEtDt]);
    //cfEnableObjects([calendar_blockCancelEtDt, calendar_blockEtDt]);			
  }
  scwin.f_Set("UPDATE");
};

