scwin.f_ChkUserPrivGroupSelect = function () {
  let vTmpSeq = 0;
  let vTmpVal;
  let vCompareVal;
  let vUserPrivGroupCountRow = ds_userPrivGroup.getRowCount();
  for (i = 0; i < vUserPrivGroupCountRow; i++) {
    vTmpVal = ds_userPrivGroup.getCellData(i, "privGrpId");
    for (j = i + 1; j < vUserPrivGroupCountRow; j++) {
      vCompareVal = ds_userPrivGroup.getCellData(j, "privGrpId");
      if (vTmpVal == vCompareVal) {
        vTmpSeq++;
      }
    }
  }
  return vTmpSeq;
};
