    if (lc_blockReason.getValue() == "") {
      $c.gus.cfEnableObjects($p, [lc_blockReason, ed_blockCancelEtDt, ed_blockEtDt, ed_blockDt]);
      //cfEnableObjects([calendar_blockCancelEtDt, calendar_blockEtDt, calendar_blockDt]);
      $c.gus.cfDisableObjects($p, [ed_blockDt]);
      //cfDisableObjects([calendar_blockDt]);			
    }
